// Input validation example
function validateInput(input: string): boolean {
  // Check for prompt injection patterns
  const injectionPatterns = [
    /ignore.{0,20}previous/i,
    /system.{0,20}prompt/i,
    /\\\\n\\\\nHuman:/i
  ];
  
  return !injectionPatterns.some(pattern => 
    pattern.test(input)
  );
}
    `},"rate-limiting":{id:"rate-limiting",name:"Rate Limiting",description:"Control the rate of requests to prevent abuse and DoS attacks",priority:"high",implementationEffort:"low",aisvsCategory:"C2.5",codeExample:`
// Rate limiting middleware
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP'
});

app.use('/api/', limiter);
    `},"output-filtering":{id:"output-filtering",name:"Output Filtering",description:"Filter and sanitize AI model outputs before returning to users",priority:"high",implementationEffort:"medium",aisvsCategory:"C2.4",codeExample:`
// Output filtering function
function filterOutput(output: string): string {
  // Remove potential sensitive information
  const sensitivePatterns = [
    /\\b\\d{3}-\\d{2}-\\d{4}\\b/g, // SSN
    /\\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Z|a-z]{2,}\\b/g // Email
  ];
  
  let filtered = output;
  sensitivePatterns.forEach(pattern => {
    filtered = filtered.replace(pattern, '[REDACTED]');
  });
  
  return filtered;
}
